var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":"추가 적성개체 접근 중! 9시와 1시 방향!","JPN":"さらなる敵性個体が接近中！　9時と1時の方角！","ENG":"Additional hostiles approaching! Nine o'clock and one o'clock!","TWN":"有追加適性體接近！9點鐘與1點鐘方向！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"다들 위치 사수해. 수가 많다곤 해도 결국 1종이다.","JPN":"全員持ち場を守れ。数が多いとはいえ、所詮は第1種だ。","ENG":"Hold your positions, everyone. Even if there are a lot of them, they're still Category 1.","TWN":"全員死守位置。它們數量雖多，但終究是1類。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":"그렇다곤 해도 이상합니다. 벌써 열 세 개의 포인트에서 동시에 침식 군체가 들이닥치고 있어요.","JPN":"でもおかしいです。すでに13か所のポイントで同時に侵食体の群れが押し寄せています。","ENG":"Even so, this is strange. C.O. swarms are hitting thirteen points simultaneously already.","TWN":"即便如此也很奇怪。已經有十三個據點同時出現侵蝕群體。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"근래 발생한 말하는 침식체 사건들에 비하면 이런 건 사랑스러운 축이지.","JPN":"近頃発生している、「言葉を話す侵食体」事件に比べたらこれくらいはかわいいほうだぞ。","ENG":"Compared to those recent talking C.O. incidents, this is almost cute.","TWN":"和最近那些會說話的侵蝕體事件相比，這種反而很可愛。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"대응할 병력은 충분해. 우리만 정신 바짝 차리면 오늘 인명 피해는 한 건도 없을 거다.","JPN":"対応する兵力は十分にある。私たちが気をしっかり持てば、今日は誰も傷つかずに済む。","ENG":"We've got sufficient forces. As long as we stay sharp, there won't be a single casualty today.","TWN":"我們兵力足夠。只要集中精神，今天不會有任何人員傷亡。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"침식현상이 발생했는데, 민가 몇 채 무너지는 정도로 그쳤군.","JPN":"侵食現象が発生したのに、民家が数件崩壊する程度で済んだな。","ENG":"A Counterside Effect occurred, yet it was limited to just a few residential buildings collapsing.","TWN":"發生侵蝕現象，但只有幾棟民宅倒塌。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그것도 다행히 대피가 빨라서 전부 빈 집이었어.","JPN":"幸い、早めに避難していて全部人がいない家だったしね。","ENG":"Luckily, evacuations were fast. All of them were empty houses.","TWN":"幸好疏散及時，全是空屋。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"강도는 약했지만 워낙 광범위한 현상이라 정화 작업은 제법 오래 걸릴 거래.","JPN":"強度は弱かったけど、範囲が広すぎて浄化作業には結構時間がかかるらしいよ。","ENG":"The intensity was low, but it covered such a wide area that purification will take quite a while.","TWN":"雖然強度不高，但範圍太廣，淨化作業會花不少時間。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…이상해.","JPN":"……おかしい。","ENG":"...Something's off.","TWN":"……有點奇怪。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"침식현상이 도시 외곽과 중심지에 동시에 발생한 경우는 지금껏 한 번도 없었어.","JPN":"侵食現象が都市外郭と中心地に同時発生したケースは今まで一度もなかった。","ENG":"There's never been a case where a Counterside Effect happened simultaneously on the outskirts and in the city center.","TWN":"這還是第一次侵蝕同時出現在郊外與市中心。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그런 초유의 사태가 이 정도로 쉽게 무마되는 게 이상하다- 라는 거지?","JPN":"そんな前代未聞の事態が、こうも簡単に収まるなんておかしいって言いたいんでしょ。","ENG":"You mean it's strange that an unprecedented situation like that got smoothed over this easily?","TWN":"這種前所未有的狀況，卻這麼輕易被壓下來—很奇怪吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"이게 눈속임이라면, 뭘 위한 속임수일까?","JPN":"もしこれが目くらましなら……何が本当の狙い何だろう……","ENG":"If this was a diversion, then what was it meant to distract us from?","TWN":"如果這是障眼法，那目的是什麼？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"병력 철수는 보류. 거수자를 찾을 때까지 수색을 재개한다.","JPN":"兵力の撤退は保留。不審者を見つけ出すまで捜索を続行する。","ENG":"Hold off on withdrawing forces. Resume the search until we find the hostile.","TWN":"暫緩撤軍。在找到舉報者前，重新展開搜索。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L25_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"알겠습니다, 시니어님.","JPN":"了解しました、シニア。","ENG":"Understood, ma'am.","TWN":"是，Senior。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그러고 보니.","JPN":"そういえば。","ENG":"Come to think of it.","TWN":"啊，對了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L27_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"동행하기로 했던 구마사는 어디로 갔지?","JPN":"同行させたエクソシストはどこだ？","ENG":"Where did the exorcist who was supposed to accompany us go?","TWN":"原本說要同行的驅魔師呢？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"가게로 돌려보냈어.","JPN":"店に帰したよ。","ENG":"I sent her back to the bar.","TWN":"我把她送回店裡了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"보냈다고?","JPN":"帰した？","ENG":"You sent her back?","TWN":"你送她回去了？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"알잖아. 누구랑 같이 다니는 건 내 성미에 안 맞는다고.","JPN":"知ってるでしょ。誰かと一緒に行動するとか性に合わないの。","ENG":"You know me. I don't like traveling with other people.","TWN":"你也知道，我不喜歡有人跟著我。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"후.","JPN":"ふう。","ENG":"Hmph.","TWN":"呵。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그 말을 곧이곧대로 받아들였다면, 진작에 보호 중인 꼬마부터 데리러 왔을 거야.","JPN":"その言葉を素直に受け入れていたなら、保護している子を真っ先に迎えに来ただろう。","ENG":"If I'd taken that at face value, I'd have already gone to retrieve the child under protection.","TWN":"要是她真的照單全收，早就跑去接走被我們保護中的小鬼了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"어…? 아직 안 데려갔어?","JPN":"え……？　迎えに来てないの？","ENG":"Huh...? You haven't picked her up yet?","TWN":"咦……？她沒去接走她嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"자기 과신에 빠져서 시니어 지시를 귓등으로 들었군.","JPN":"慢心ゆえにシニアの指示を聞き流したな。","ENG":"You let your overconfidence make you ignore a Senior's orders.","TWN":"你真是自信過頭，把Senior的命令當耳邊風了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그 여자를 붙여준 건 데리고 다니면서 감시하라는 거지. 너한테 도움이 되길 바랐던 게 아니란 말이다.","JPN":"彼女を同行させたのは傍において監視しろという意味であって、お前の役に立つと思ったからではない。","ENG":"I assigned her to you so you could keep her with you and monitor her. It wasn't meant to help you.","TWN":"我讓你帶著她，是要你一邊行動一邊監視她，不是要她幫你。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"아오, 난장맞을! 그럼 제대로 그렇게 말해주던가!","JPN":"このたわけ者めが！　なら最初からはっきりそう言えっての！","ENG":"Ugh, darn it! Then you should've said that properly from the start!","TWN":"可惡！那你一開始就該說清楚啊！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"subtitle","speaker":null,"text":{"KOREA":"그라운드 원 관리 1구역, 대균열 억제기 보안문","JPN":"グラウンド・ワン管理第1区域、大亀裂抑制装置セキュリティドア","ENG":"Ground One Managed Zone 1, Grand Dimension Crevice Inhibitor Security Gate","TWN":"G1管理區第1區，大峽谷抑制器安全門。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CULTIST_NPC_NULL_ENTER","text":{"KOREA":"불신자들은 작은 파문을 살피는데 여념이 없다.","JPN":"不信者たちは小さき波紋を見定めるために苦心している。","ENG":"The unbelievers are too busy chasing minor disturbances.","TWN":"未信者們正忙著觀察細微的波紋。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CULTIST_NPC_NULL_ENTER","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"CULTIST_NPC_NULL_SPEAK","text":{"KOREA":"때가 되었다.","JPN":"時が来た。","ENG":"The time has come.","TWN":"時候到了。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":{"char_id":"CULTIST_NPC_NULL_ENTER","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L47_1","type":"dialog","speaker":"CULTIST_NPC_NULL_SPEAK","text":{"KOREA":"암군의 사도가 안배한 성소에 우리의 독을 풀어, 그분의 뜻을 남김없이 행하리라.","JPN":"暗君の使徒が手配した聖所に我らの毒を撒き、あのお方の志を全うせん。","ENG":"We shall release our venom into the sanctum prepared by the Ignorant Monarch's Apostle, and carry out her will without omission.","TWN":"在暗軍使徒安排的聖所中散布我們的毒素，完整執行那位的意志。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":{"char_id":"CULTIST_NPC_NULL_ENTER","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_QM","text":{"KOREA":"…이런 곳에 있었군요.","JPN":"……こんなところにいたんですね。","ENG":"...So this is where you were hiding.","TWN":"……原來在這種地方啊。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":{"char_id":"CULTIST_NPC_NULL_ENTER","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"그 보안문 너머가 세상에서 가장 위험한 대균열이라는 건 외지 사람인 저도 알아요.","JPN":"そのセキュリティドアの向こうが世界で最も危険な大亀裂だってことは、ここの出身じゃない私にもわかります。","ENG":"Even an outsider like me knows that beyond that security gate lies the most dangerous Grand Dimension Crevice in the world.","TWN":"連我這個外人都知道，那扇門後是世上最危險的大峽谷。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"관계자 외 출입금지라는 표시를 보고도, 거길 들어갈 셈인가요?","JPN":"関係者以外立入禁止のプレートを見ても、そこに入るつもりですか？","ENG":"You saw the sign saying authorized personnel only, and you still intend to go in?","TWN":"即使看到非相關人員禁止進入的標示，還是打算闖入嗎？"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CULTIST_NPC_NULL_SPEAK","text":{"KOREA":"옛 낙원의 성자여. 우리를 어떻게 찾았나?","JPN":"かつての楽園の聖者よ、いかにして我らを探し出した？","ENG":"Helgon of the fallen Promise Land. How did you find us?","TWN":"昔日樂園的聖者啊，你是怎麼找到我們的？"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"관리국 분들의 말씀으론 당신들이 도시 내부의 구조를 전부 파악하고 있다더군요.","JPN":"管理局の方々の話によると、あなたたちは都市内部の構造をすべて把握しているらしいですね。","ENG":"According to the Administration, you've already mapped out the city's entire internal layout.","TWN":"管理局的人說，你們已經掌握了整座城市的內部構造。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"마음만 먹으면 사각지대로 몸을 숨길 수 있을 텐데 갑자기 관리국의 눈에 띈다는 건…","JPN":"その気になればいつでも死角に隠れることができるのに、急に管理局の目につくような行動をし出したということは……","ENG":"If you wished, you could hide yourselves in blind spots with ease. So to suddenly draw the Administration's attention means...","TWN":"只要有心，應該能藏在死角。卻偏偏主動引起管理局注意……"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"도시의 주의를 다른 곳으로 돌리고 싶다는 뜻이겠죠.","JPN":"陽動を目的としているからですよね。","ENG":"You wanted to divert the city's focus elsewhere.","TWN":"那也就表示你們是想引開城市的目光。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CULTIST_NPC_NULL_SPEAK","text":{"KOREA":"…또다시 거룩한 의지에 무가치한 훼방을 놓으려는가.","JPN":"……またもや聖なる意志に下らない抵抗をするのか。","ENG":"...Do you intend to interfere with the sacred will once more?","TWN":"……你又要對神聖的意志做出無謂的干涉嗎？"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"사람을 고깃덩이 정도로 여기는 당신들이 어떤 신을 믿고 따르건-","JPN":"人を肉の塊としか見ていないあなたたちがどんな神を信じていようが……","ENG":"Whatever god you worship, if you see humans as nothing more than slabs of meat...","TWN":"把人當成肉塊的你們，不管信奉什麼神—"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…저에겐 맞서야 할 이단일 뿐이니까요.","JPN":"私にとっては、立ち向かうべき異端にすぎません。","ENG":"...Then to me, you're nothing but heretics I must oppose.","TWN":"……對我而言，都只是必須對抗的異端。"},"stage":{"bg":"TERRA","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};